import{_ as e}from"./chunks/12-tui-health-check.B9ksbbcn.js";import{_ as r,o,c as n,a2 as a}from"./chunks/framework.DTa47_fH.js";const m=JSON.parse('{"title":"Health Check","description":"","frontmatter":{},"headers":[],"relativePath":"health-check.md","filePath":"health-check.md"}'),s={name:"health-check.md"};function i(d,t,h,c,l,p){return o(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="health-check" tabindex="-1">Health Check <a class="header-anchor" href="#health-check" aria-label="Permalink to &quot;Health Check&quot;">​</a></h1><p>Health Check verifies that every component of your SWAO environment is working correctly before you run an assessment. Run it after setup, after any configuration change, and before a session to confirm the environment is ready.</p><p>Access it from the TUI main menu by pressing <strong>2</strong>, or from the command line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao health-check</span></span></code></pre></div><p><img src="'+e+'" alt="SWAO Health Check results"></p><hr><h2 id="the-11-probes" tabindex="-1">The 11 probes <a class="header-anchor" href="#the-11-probes" aria-label="Permalink to &quot;The 11 probes&quot;">​</a></h2><p>Health Check runs 11 automated checks and reports one of three statuses for each:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>OK</strong></td><td>Component is configured and working correctly.</td></tr><tr><td><strong>WARN</strong></td><td>Something needs attention before assessment will work as expected.</td></tr><tr><td><strong>INFO</strong></td><td>An optional component is not configured -- assessment continues without it.</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Probe</th><th>What it checks</th></tr></thead><tbody><tr><td><strong>[1/11] Licence</strong></td><td>Licence tier (Community / Consultant / Enterprise), usage count, and expiry date.</td></tr><tr><td><strong>[2/11] Playwright / Chromium</strong></td><td>Whether Playwright is installed. Required for PDF report generation and the HTML Editor.</td></tr><tr><td><strong>[3/11] SWAO-MCP</strong></td><td>Whether the SWAO MCP server is registered and reachable. Required for Claude Desktop integration.</td></tr><tr><td><strong>[4/11] Compliance catalogues</strong></td><td>Integrity of all installed framework YAML files. Reports the framework name, contributor, and control count for each one.</td></tr><tr><td><strong>[5/11] Import templates</strong></td><td>Whether Power BI <code>.pbit</code> template files are present in <code>wsp/templates/powerbi/</code>.</td></tr><tr><td><strong>[6/11] Traceability</strong></td><td>Whether assessed applications meet the traceability targets (signal count thresholds that confirm the assessment is substantive).</td></tr><tr><td><strong>[7/11] BI export</strong></td><td>Whether the star-schema export bundle is present and internally consistent (row counts and hashes).</td></tr><tr><td><strong>[8/11] Scope</strong></td><td>Whether Pass 13 (scope coverage) has been run for each application. Scope coverage is emitted by default from v0.4.5+.</td></tr><tr><td><strong>[9/11] Prerequisites</strong></td><td>Whether optional command-line tools are on the PATH (e.g. <code>ssh</code> for key-based repository cloning).</td></tr><tr><td><strong>[10/11] VCS auth</strong></td><td>Whether SWAO can authenticate to the version control hosts configured for your applications.</td></tr><tr><td><strong>[11/11] Audit ingestion</strong></td><td>Whether an audit workspace ingestion folder is configured. Only relevant for Audit Assessment.</td></tr></tbody></table><hr><h2 id="machine-fingerprint" tabindex="-1">Machine fingerprint <a class="header-anchor" href="#machine-fingerprint" aria-label="Permalink to &quot;Machine fingerprint&quot;">​</a></h2><p>At the bottom of every Health Check output, SWAO displays a <strong>machine fingerprint</strong> -- a short identifier tied to the hardware running SWAO. This fingerprint is required when requesting a licence key upgrade. Keep a note of it for your records.</p><hr><h2 id="responding-to-warn-and-info" tabindex="-1">Responding to WARN and INFO <a class="header-anchor" href="#responding-to-warn-and-info" aria-label="Permalink to &quot;Responding to WARN and INFO&quot;">​</a></h2><p>Each probe that does not return OK displays guidance text explaining what needs to be done. You can press <strong>Ctrl+G</strong> in the TUI view to expand the guidance box for the selected probe.</p><p>Common resolutions:</p><ul><li><strong>Playwright WARN</strong> -- run <code>npx playwright install chromium</code> or use the Workspace Setup wizard (Step 6).</li><li><strong>VCS auth WARN</strong> -- re-run Workspace Setup Step 3 (Credentials) to refresh repository credentials.</li><li><strong>Scope INFO</strong> -- run <code>swao assess --app &lt;id&gt;</code> to generate scope coverage for the listed applications.</li><li><strong>Audit ingestion INFO</strong> -- only relevant if you intend to run an Audit Assessment; safe to ignore otherwise.</li></ul><p>&quot;All probes passed&quot; confirms the workspace is ready for assessment.</p>',19)])])}const f=r(s,[["render",i]]);export{m as __pageData,f as default};
